const EXCLUIDOS = ['C3'];
const todos = $input.all().map(item => item.json).filter(c => !EXCLUIDOS.includes(c.consultor_key));
const totalLeads = todos.reduce((sum, c) => sum + (c.total_leads || 0), 0);
const isAssessores = (totalLeads % 5) === 4;
const candidatos = todos.filter(c => isAssessores ? c.time === 'assessores' : c.time === 'consorcio');
if (candidatos.length === 0) {
  throw new Error(`Nenhum consultor disponível para time: ${isAssessores ? 'assessores' : 'consorcio'}`);
}
candidatos.sort((a, b) => {
  if (!a.dt_ultimo_lead && !b.dt_ultimo_lead) return 0;
  if (!a.dt_ultimo_lead) return -1;
  if (!b.dt_ultimo_lead) return 1;
  return new Date(a.dt_ultimo_lead) - new Date(b.dt_ultimo_lead);
});
const escolhido = candidatos[0];
return [{ json: { consultor_key: escolhido.consultor_key, nome_consultor: escolhido.nome_consultor, enum_id: escolhido.enum_id, time: escolhido.time, pipeline_id: escolhido.pipeline_id, status_id: escolhido.status_id, total_leads_atual: escolhido.total_leads || 0 } }];

const mergeLeadOutput = $input.first().json;
let kommo_lead_id = null;
if (mergeLeadOutput._embedded?.leads?.[0]?.id) {
  kommo_lead_id = mergeLeadOutput._embedded.leads[0].id;
} else if (Array.isArray(mergeLeadOutput) && mergeLeadOutput[0]?.id) {
  kommo_lead_id = mergeLeadOutput[0].id;
} else if (mergeLeadOutput.id) {
  kommo_lead_id = mergeLeadOutput.id;
}
const wh = $('Webhook - Formulário').first().json;
const consultor = $('Calcular Consultor').first().json;
const contact_id = $('Merge Contato').first().json.contact_id;
return [{ json: {
  lead_id: kommo_lead_id,
  contact_id,
  form_name: 'Formulário Consórcio',
  pipeline_id: consultor.pipeline_id,
  status_id: consultor.status_id,
  nome: wh.nome || null,
  whatsapp: wh.whatsapp || null,
  email: wh.email || null,
  fbclid: wh.fbclid || null,
  gclid: wh.gclid || null,
  utm_source: wh.utm_source || null,
  utm_medium: wh.utm_medium || null,
  utm_campaign: wh.utm_campaign || null,
  utm_content: wh.utm_content || null,
  utm_term: wh.utm_term || null,
  pagina: wh.pagina || null,
  timestamp_form: wh.timestamp_form ? new Date(wh.timestamp_form).toISOString() : new Date().toISOString(),
  simulacao_tipo: wh.simulacao?.tipo || null,
  simulacao_credito: wh.simulacao?.credito || null,
  simulacao_prazo: wh.simulacao?.prazo || null,
  simulacao_parcela_cheia: wh.simulacao?.parcelaCheia || null,
  finalidade: wh.finalidade || null,
  cidade_consorcio: wh.cidade_consorcio || null,
  estado: wh.estado || null,
  cidade: wh.cidade || null,
  perfil: wh.perfil || null,
  lgpd_consent: wh.lgpd_consent || null,
  convertido: false
} }];
